import * as fs from 'fs';

enum TokenType {
    NUMBER,
    UPLUS,
    UMINUS,
    BPLUS,
    BMINUS,
    MULTIPLY,
    DIVIDE,
    LPAREN,
    RPAREN,
    END
}

interface Token {
    type: TokenType;
    value: number | null;
}

function tokenize(input: string): Token[] {
    const tokens: Token[] = [];
    let i = 0;
    while (i < input.length) {
        const ch = input[i];
        if (ch === ' ') {
            i++;
            continue;
        }
        if (ch >= '0' && ch <= '9') {
            let num = 0;
            while (i < input.length && input[i] >= '0' && input[i] <= '9') {
                num = num * 10 + (input[i] - '0');
                i++;
            }
            tokens.push({ type: TokenType.NUMBER, value: num });
            continue;
        }
        if (ch === '+' || ch === '-') {
            // Determine if unary or binary
            // Unary if at start, after LPAREN, or after another operator
            const isUnary = tokens.length === 0 ||
                tokens[tokens.length - 1].type === TokenType.LPAREN ||
                tokens[tokens.length - 1].type === TokenType.UPLUS ||
                tokens[tokens.length - 1].type === TokenType.UMINUS ||
                tokens[tokens.length - 1].type === TokenType.BPLUS ||
                tokens[tokens.length - 1].type === TokenType.BMINUS ||
                tokens[tokens.length - 1].type === TokenType.MULTIPLY ||
                tokens[tokens.length - 1].type === TokenType.DIVIDE;
            if (isUnary) {
                if (ch === '+') {
                    tokens.push({ type: TokenType.UPLUS, value: null });
                } else {
                    tokens.push({ type: TokenType.UMINUS, value: null });
                }
            } else {
                if (ch === '+') {
                    tokens.push({ type: TokenType.BPLUS, value: null });
                } else {
                    tokens.push({ type: TokenType.BMINUS, value: null });
                }
            }
            i++;
            continue;
        }
        if (ch === '*') {
            tokens.push({ type: TokenType.MULTIPLY, value: null });
            i++;
            continue;
        }
        if (ch === '/') {
            tokens.push({ type: TokenType.DIVIDE, value: null });
            i++;
            continue;
        }
        if (ch === '(') {
            tokens.push({ type: TokenType.LPAREN, value: null });
            i++;
            continue;
        }
        if (ch === ')') {
            tokens.push({ type: TokenType.RPAREN, value: null });
            i++;
            continue;
        }
        i++; // skip unknown characters
    }
    return tokens;
}

function getPrecedence(type: TokenType): number {
    switch (type) {
        case TokenType.UPLUS:
        case TokenType.UMINUS:
            return 3;
        case TokenType.MULTIPLY:
        case TokenType.DIVIDE:
            return 2;
        case TokenType.BPLUS:
        case TokenType.BMINUS:
            return 1;
        default:
            return 0;
    }
}

function isLeftAssociative(type: TokenType): boolean {
    switch (type) {
        case TokenType.BPLUS:
        case TokenType.BMINUS:
        case TokenType.MULTIPLY:
        case TokenType.DIVIDE:
            return true;
        default:
            return false;
    }
}

function isOperator(type: TokenType): boolean {
    return type === TokenType.UPLUS || type === TokenType.UMINUS ||
        type === TokenType.BPLUS || type === TokenType.BMINUS ||
        type === TokenType.MULTIPLY || type === TokenType.DIVIDE;
}

function shuntingYard(tokens: Token[]): Token[] {
    const output: Token[] = [];
    const opStack: Token[] = [];

    for (const token of tokens) {
        if (token.type === TokenType.NUMBER) {
            output.push(token);
        } else if (isOperator(token.type)) {
            while (opStack.length > 0 && isOperator(opStack[opStack.length - 1].type)) {
                const top = opStack[opStack.length - 1];
                if (getPrecedence(top.type) > getPrecedence(token.type) ||
                    (getPrecedence(top.type) === getPrecedence(token.type) && isLeftAssociative(token.type))) {
                    output.push(opStack.pop()!);
                } else {
                    break;
                }
            }
            opStack.push(token);
        } else if (token.type === TokenType.LPAREN) {
            opStack.push(token);
        } else if (token.type === TokenType.RPAREN) {
            while (opStack.length > 0 && opStack[opStack.length - 1].type !== TokenType.LPAREN) {
                output.push(opStack.pop()!);
            }
            if (opStack.length > 0) {
                opStack.pop(); // pop LPAREN
            }
        }
    }

    while (opStack.length > 0) {
        output.push(opStack.pop()!);
    }

    return output;
}

function evaluateRPN(rpn: Token[]): number {
    const stack: number[] = [];

    for (const token of rpn) {
        if (token.type === TokenType.NUMBER) {
            stack.push(token.value!);
        } else if (token.type === TokenType.UPLUS) {
            const a = stack.pop()!;
            stack.push(+a);
        } else if (token.type === TokenType.UMINUS) {
            const a = stack.pop()!;
            stack.push(-a);
        } else if (token.type === TokenType.BPLUS) {
            const b = stack.pop()!;
            const a = stack.pop()!;
            stack.push(a + b);
