            const b = stack.pop()!;
            const a = stack.pop()!;
            stack.push(a * b);
        } else if (token.type === TokenType.DIVIDE) {
            const b = stack.pop()!;
            const a = stack.pop()!;
            // Truncate toward zero
            stack.push(Math.trunc(a / b));
        }
    }

    return stack[0];
}

